package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author string
	Body   string
}

var comments []Comment

func commentHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := template.Must(template.ParseFiles("comments.html"))
	tmpl.Execute(w, comments)
}

func main() {
	comments = []Comment{
		{"John Doe", "This is a great website!"},
		{"Jane Smith", "I love your content!"},
	}

	http.HandleFunc("/comments", commentHandler)
	http.ListenAndServe(":8080", nil)
}